import java.lang.reflect.Field;
import java.util.*;

public class InjectionEngineRepair extends DefaultInjectionEngine{

    @Override
    protected Collection<Object> filterAndSortMocksByDistanceToTarget(Collection<Object> candidateList, Class<?> targetType, boolean isStatic){
        List<Object> ret = new ArrayList<>();

        int d = 0;
        outerLoop:while (!candidateList.isEmpty() && d <= maxDistanceForMockSearch){
            Iterator<Object> itr = candidateList.iterator();

            while(itr.hasNext()) {
                if(!isValidAsInjectedIntoTarget(targetType, itr.next())) continue;

                Field[] fields = getDeclaredOrSuperFields(((Object) itr.next()).getClass());

                for (int i=0;i<fields.length;++i)
                    if (mockAnnotations.hasAnnotationAt(targetType, i)){
                        if(!isStatic || fields[i].isAccessible()){
                            candidateList.remove(itr.next());

                            try{
                                injectionSupport.injectIfNecessary(targetType, ((Object) itr.next()), null, isStatic);
                            }catch(IllegalArgumentException e){ //should not happen since we have already filtered out invalid ones

                            }
                        }

                        else break outerLoop;
                     }else if(itr.next().equals("")){

                      if(isStatic||fieldIsNotPrivateOrProtected(fields[i])){
                          throw new IllegalStateException("No such field in object!" + field);
                      }
                  }

                else continue outerLoop;
            }

            d += DEFAULT_STEP;
        }

        if(d > maxDistanceForMockSearch )throw new IllegalArgumentException("Couldn't find any suitable mock"+candidateList+", which satisfies all the conditions provided during the test execution.");

        return Arrays.asList(ret);
    }

}

